customCSS:
/* Nebula Command - Stellar Ops Command Console */
@import url('https://fonts.googleapis.com/css2?family=Titillium+Web:wght@400;600;700&family=Exo+2:wght@300;400;600;700&display=swap');

/* Starfield ambient */
.cyber-grid {
  background: none;
  animation: none;
}

.cyber-glow {
  background:
    radial-gradient(ellipse 600px 400px at 30% 20%, rgba(68, 136, 255, 0.06), transparent),
    radial-gradient(ellipse 400px 250px at 75% 75%, rgba(153, 68, 255, 0.04), transparent),
    radial-gradient(circle 2px at 10% 15%, rgba(255, 255, 255, 0.2), transparent),
    radial-gradient(circle 1px at 30% 45%, rgba(200, 220, 255, 0.15), transparent),
    radial-gradient(circle 2px at 55% 10%, rgba(255, 255, 255, 0.18), transparent),
    radial-gradient(circle 1px at 70% 35%, rgba(200, 220, 255, 0.12), transparent),
    radial-gradient(circle 1px at 90% 60%, rgba(255, 255, 255, 0.1), transparent),
    radial-gradient(circle 2px at 15% 80%, rgba(200, 220, 255, 0.14), transparent),
    radial-gradient(circle 1px at 45% 85%, rgba(255, 255, 255, 0.08), transparent),
    radial-gradient(circle 1px at 85% 15%, rgba(200, 220, 255, 0.1), transparent);
}

/* Plasma energy strip on stat cards */
.stat-card {
  border: 1px solid rgba(68, 136, 255, 0.15);
  border-left: 3px solid #4488ff;
  border-radius: 4px;
  position: relative;
}

.stat-card::before {
  background: linear-gradient(90deg, #4488ff, #00ccff);
  height: 2px;
  border-radius: 4px 4px 0 0;
}

/* Alternating energy colors on miner cards */
.miner-card {
  border: 1px solid rgba(68, 136, 255, 0.12);
  border-left: 3px solid #4488ff;
  border-radius: 4px;
}

.miner-card:nth-child(even) {
  border-left-color: #44ff44;
}

.miner-card:nth-child(3n) {
  border-left-color: #9944ff;
}

/* Health and lifetime cards */
.health-card,
.lifetime-card {
  border: 1px solid rgba(68, 136, 255, 0.12);
  border-radius: 4px;
}

/* Projected hover glow */
.stat-card:hover {
  border-color: rgba(68, 136, 255, 0.4);
  box-shadow:
    0 0 20px rgba(68, 136, 255, 0.15),
    0 0 40px rgba(68, 136, 255, 0.05);
}

.miner-card:hover {
  border-color: rgba(153, 68, 255, 0.35);
  box-shadow:
    0 0 15px rgba(153, 68, 255, 0.12),
    0 0 30px rgba(153, 68, 255, 0.04);
}

/* Stat values — stellar blue glow */
.stat-value {
  text-shadow: 0 0 12px rgba(68, 136, 255, 0.5), 0 0 25px rgba(68, 136, 255, 0.2);
}

/* Section headers — gradient underline */
.section-header h2 {
  position: relative;
  padding-bottom: 0.6rem;
}

.section-header h2::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 60px;
  height: 3px;
  background: linear-gradient(90deg, #4488ff, #9944ff, transparent);
  border-radius: 2px;
}

/* Alert red for offline miners */
.miner-status-dot.offline {
  box-shadow: 0 0 8px rgba(255, 34, 68, 0.7), 0 0 16px rgba(255, 34, 68, 0.3);
}

.miner-card.offline {
  border-left-color: #ff2244;
}

/* Celebration — golden nova burst */
.celebration-title {
  color: #ffcc00 !important;
  text-shadow: 0 0 30px rgba(255, 204, 0, 0.6), 0 0 60px rgba(255, 136, 0, 0.3) !important;
}

.celebration-icon {
  filter: hue-rotate(45deg) brightness(1.3);
}

/* Command console logo */
.logo {
  text-shadow: 0 0 20px rgba(68, 136, 255, 0.4), 0 0 40px rgba(68, 136, 255, 0.15);
  letter-spacing: 4px;
}

/* Star particle styling */
.cyber-particles {
  opacity: 0.5;
}

/* Alert badges — warning amber */
.badge {
  border-color: rgba(255, 136, 0, 0.3);
  letter-spacing: 1px;
}

/* Scrollbar — stellar track */
::-webkit-scrollbar-thumb {
  background: rgba(68, 136, 255, 0.3);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(68, 136, 255, 0.5);
}
